import 'package:flutter/material.dart';import 'category.dart';class Transaction {  final String id;  final String merchant;  final DateTime date;  final double amount;  final Category category;  final String? description;  final String? receiptImageUrl;  final List<String> tags;  Transaction({    required this.id,    required this.merchant,    required this.date,    required this.amount,    required this.category,    this.description,    this.receiptImageUrl,    this.tags = const [],  });  Transaction copyWith({    String? id,    String? merchant,    DateTime? date,    double? amount,    Category? category,    String? description,    String? receiptImageUrl,    List<String>? tags,  }) {    return Transaction(      id: id ?? this.id,      merchant: merchant ?? this.merchant,      date: date ?? this.date,      amount: amount ?? this.amount,      category: category ?? this.category,      description: description ?? this.description,      receiptImageUrl: receiptImageUrl ?? this.receiptImageUrl,      tags: tags ?? this.tags,    );  }}